CREATE OR REPLACE VIEW public.eclectic_scores_view AS
 SELECT tournament_id,
    player_id,
    hole_number,
    min(strokes) AS best_strokes
   FROM public.scores
  GROUP BY tournament_id, player_id, hole_number;

