CREATE TABLE IF NOT EXISTS public.ops_alert_settings (
    id integer DEFAULT 1 NOT NULL,
    notify_exhaustion_threshold integer,
    notify_exhaustion_window_hours integer,
    updated_by_user_id integer,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    manual_entry_rate_threshold_pct integer,
    manual_entry_min_sample integer,
    manual_entry_consecutive_zero integer,
    manual_entry_cooldown_hours integer,
    CONSTRAINT ops_alert_settings_me_consecutive_zero_chk CHECK (((manual_entry_consecutive_zero IS NULL) OR (manual_entry_consecutive_zero > 0))),
    CONSTRAINT ops_alert_settings_me_cooldown_hours_chk CHECK (((manual_entry_cooldown_hours IS NULL) OR (manual_entry_cooldown_hours > 0))),
    CONSTRAINT ops_alert_settings_me_min_sample_chk CHECK (((manual_entry_min_sample IS NULL) OR (manual_entry_min_sample > 0))),
    CONSTRAINT ops_alert_settings_me_rate_threshold_chk CHECK (((manual_entry_rate_threshold_pct IS NULL) OR ((manual_entry_rate_threshold_pct > 0) AND (manual_entry_rate_threshold_pct <= 100)))),
    CONSTRAINT ops_alert_settings_singleton_chk CHECK ((id = 1)),
    CONSTRAINT ops_alert_settings_threshold_positive_chk CHECK (((notify_exhaustion_threshold IS NULL) OR (notify_exhaustion_threshold > 0))),
    CONSTRAINT ops_alert_settings_window_positive_chk CHECK (((notify_exhaustion_window_hours IS NULL) OR (notify_exhaustion_window_hours > 0)))
);

